const fs = require('fs');
const path = require('path');

const basePath = 'D:\\ProjetosWebfull';
const projects = [];

if (!fs.existsSync(basePath)) {
  return [{ json: { projects: [], error: 'Pasta não encontrada' } }];
}

const dirs = fs.readdirSync(basePath, { withFileTypes: true });

for (const dir of dirs) {
  if (!dir.isDirectory()) continue;
  const projectPath = path.join(basePath, dir.name);

  let type = 'unknown';
  let techStack = [];
  let wpVersion = null;
  let themeName = null;
  let plugins = [];
  let gitRepo = null;

  // Detecta tipo de projeto
  if (fs.existsSync(path.join(projectPath, 'package.json'))) {
    type = 'nodejs';
    try {
      const pkg = JSON.parse(fs.readFileSync(path.join(projectPath, 'package.json'), 'utf-8'));
      if (pkg.dependencies?.next) type = 'nextjs';
      if (pkg.dependencies?.react) techStack.push('React');
      if (pkg.dependencies?.express) techStack.push('Express');
      if (pkg.dependencies?.vue) techStack.push('Vue');
    } catch {}
  } else if (fs.existsSync(path.join(projectPath, 'composer.json'))) {
    type = 'php';
    try {
      const composer = JSON.parse(fs.readFileSync(path.join(projectPath, 'composer.json'), 'utf-8'));
      if (composer.require?.laravel) type = 'laravel';
    } catch {}
  } else if (fs.existsSync(path.join(projectPath, 'wp-config.php'))) {
    type = 'wordpress';
    // Extrai versão WP
    try {
      const versionPath = path.join(projectPath, 'wp-includes', 'version.php');
      if (fs.existsSync(versionPath)) {
        const content = fs.readFileSync(versionPath, 'utf-8');
        const match = content.match(/\$wp_version\s*=\s*['"]([^'"]+)['"]/);
        if (match) wpVersion = match[1];
      }
    } catch {}
    // Extrai tema
    try {
      const themePath = path.join(projectPath, 'wp-content', 'themes');
      if (fs.existsSync(themePath)) {
        const themes = fs.readdirSync(themePath).filter(f => {
          try { return fs.statSync(path.join(themePath, f)).isDirectory(); } catch { return false; }
        });
        const activeTheme = themes.find(t => fs.existsSync(path.join(themePath, t, 'style.css')));
        if (activeTheme) {
          const styleCss = fs.readFileSync(path.join(themePath, activeTheme, 'style.css'), 'utf-8');
          const match = styleCss.match(/Theme Name:\s*([^\n]+)/);
          themeName = match ? match[1].trim() : activeTheme;
        }
      }
    } catch {}
    // Plugins
    try {
      const pluginsPath = path.join(projectPath, 'wp-content', 'plugins');
      if (fs.existsSync(pluginsPath)) {
        plugins = fs.readdirSync(pluginsPath).filter(f => {
          try { return fs.statSync(path.join(pluginsPath, f)).isDirectory(); } catch { return false; }
        });
      }
    } catch {}
  } else if (fs.existsSync(path.join(projectPath, 'requirements.txt'))) {
    type = 'python';
  } else if (fs.existsSync(path.join(projectPath, 'go.mod'))) {
    type = 'go';
  } else if (fs.existsSync(path.join(projectPath, 'Cargo.toml'))) {
    type = 'rust';
  }

  // Git remote
  try {
    const gitConfig = path.join(projectPath, '.git', 'config');
    if (fs.existsSync(gitConfig)) {
      const config = fs.readFileSync(gitConfig, 'utf-8');
      const match = config.match(/url\s*=\s*(.+)/);
      if (match) gitRepo = match[1].trim();
    }
  } catch {}

  if (type !== 'unknown') {
    projects.push({
      name: dir.name,
      path: projectPath,
      type: type,
      techStack: techStack,
      wpVersion: wpVersion,
      themeName: themeName,
      plugins: plugins,
      gitRepo: gitRepo,
      isValid: true
    });
  }
}

return [{ json: { projects } }];

const result = $input.first().json;
const count = result.results?.filter(r => r.success).length || 0;

return [
  {
    json: {
      message: count + ' projetos sincronizados',
      timestamp: new Date().toISOString(),
      results: result.results
    }
  }
];
